IF NOT EXISTS (SELECT 1 FROM comptabilite WHERE IDCOMPTABILITE = 1)
BEGIN
    SET IDENTITY_INSERT comptabilite ON;
    INSERT INTO comptabilite (
        IDCOMPTABILITE, DATEOPERATION, DEBIT, CREDIT, LIBELLE,
        agence, ETAT, CODE_SENS, VERSION, planComptable
    )
    VALUES (
        1, CAST(GETDATE() AS DATE), 0.0000, 0.0000, N'DEV — squelette pour tests caisse',
        N'NKC', N'VALIDE', N'D', 0, N'101100'
    );
    SET IDENTITY_INSERT comptabilite OFF;
END
